=Voici les caractéristiques JSON de l'image : {{ JSON.stringify($json) }}

Analyse et choisis la meilleure stratégie de compression en privilégiant la qualité visuelle.

Réponds UNIQUEMENT avec le JSON demandé.

parameters.jsCode:
const data = $input.first().json;
const f = data.features;

const features_clean = {
  type_image: f.type_image,
  taille_kb: f.metadonnees.taille_kb,
  format_original: f.metadonnees.format,
  entropy: f.features_statistiques.entropy,
  contient_texte: f.ocr.contient_texte,
  ratio_complexite: f.morphologie.ratio_complexite
};

const safe = JSON.stringify(features_clean).replace(/[^\x00-\x7F]/g, "");

return [{ json: JSON.parse(safe) }];

function extractJSON(rawOutput) {
  if (typeof rawOutput !== "string") return rawOutput;

  const match = rawOutput.match(/\{[\s\S]*"format"[\s\S]*\}/);
  if (!match) return {};

  try {
    const cleaned = match[0]
      .replace(/\\n/g, ' ')
      .replace(/\\"/g, '"')
      .replace(/\s+/g, ' ');
    return JSON.parse(cleaned);
  } catch {
    return {
      format: rawOutput.match(/"format":\s*"([^"]+)"/)?.[1] || '',
      qualite: parseInt(rawOutput.match(/"qualite":\s*(\d+)/)?.[1] || '0'),
      justification: rawOutput.match(/"justification":\s*"([^"]+)"/)?.[1] || '',
      pertinence: rawOutput.match(/"pertinence":\s*"([^"]+)"/)?.[1] || ''
    };
  }
}

const llm1 = extractJSON($('AI Agent').item.json.output);
const llm2 = extractJSON($('AI Agent1').item.json.output);

function score(p) {
  if (!p) return 0;
  p = p.toLowerCase();
  if (p.includes("élevée")) return 3;
  if (p.includes("moyenne")) return 2;
  if (p.includes("faible")) return 1;
  return 0;
}

function formatScore(format) {
  if (!format) return 0;
  format = format.toLowerCase();
  if (format === "avif") return 4;
  if (format === "webp") return 3;
  if (format === "jpeg") return 2;
  if (format === "png") return 1;
  return 0;
}

const score1 = score(llm1.pertinence);
const score2 = score(llm2.pertinence);

let decision, source, raison;

if (score1 > score2) {
  decision = llm1; source = "LLM1"; raison = "Pertinence plus élevée";
} else if (score2 > score1) {
  decision = llm2; source = "LLM2"; raison = "Pertinence plus élevée";
} else {
  const f1 = formatScore(llm1.format);
  const f2 = formatScore(llm2.format);
  if (f1 >= f2) {
    decision = llm1; source = "LLM1"; raison = "Format plus optimisé";
  } else {
    decision = llm2; source = "LLM2"; raison = "Format plus optimisé";
  }
}

return [{
  json: {
    decision_finale: {
      format: decision.format,
      qualite: decision.qualite
    },
    source,
    raison,
    detail: { llm1, llm2 }
  }
}];

const rawOutput = $input.item.json.output;

function extractJSON(raw) {
  if (typeof raw !== "string") return raw;
  const match = raw.match(/\{[\s\S]*"format"[\s\S]*\}/);
  if (!match) return {};
  try {
    const cleaned = match[0].replace(/\\n/g, ' ').replace(/\\"/g, '"').replace(/\s+/g, ' ');
    return JSON.parse(cleaned);
  } catch {
    return {
      format: raw.match(/"format":\s*"([^"]+)"/)?.[1] || '',
      qualite: parseInt(raw.match(/"qualite":\s*(\d+)/)?.[1] || '0'),
      justification: raw.match(/"justification":\s*"([^"]+)"/)?.[1] || '',
      pertinence: raw.match(/"pertinence":\s*"([^"]+)"/)?.[1] || ''
    };
  }
}

const result = extractJSON(rawOutput);
return { json: result };
